<template>
    <el-dialog
      v-model="dialogVisible"
      :title="isEdit ? '编辑AI助理' : '添加AI助理'"
      width="500px"
    >
      <div class="staff-form">
        <!-- 员工名称 -->
        <div class="form-item">
          <h3>*员工名称</h3>
          <el-input v-model="staffForm.name" placeholder="如：培育AI助理" />
        </div>
        
        <!-- 回复范围 -->
        <div class="form-item">
          <h3>*回复范围</h3>
          <el-radio-group v-model="staffForm.chatType">
            <el-radio label="single">单聊</el-radio>
            <el-radio label="group">群聊</el-radio>
          </el-radio-group>
          
          <!-- 是否读取群成员 -->
          <div v-if="staffForm.chatType === 'group'" style="margin-top: 6px; padding-top: 6px; border-top: 1px dashed #eee;">
            <el-checkbox v-model="staffForm.readGroupMember">
              是否读群成员
            </el-checkbox>
            <div class="description" style="margin-top: 4px; color: #909399; font-size: 12px;">
              微信4.1无法直接读取群聊发送者名称，需额操作获取，如非必须可不勾选
            </div>
            <!-- 是否引用回复 -->
            <div style="margin-top: 6px; padding-top: 6px; border-top: 1px dashed #eee;">
              <el-checkbox v-model="staffForm.quoteReply">
                是否引用回复
              </el-checkbox>
              <div class="description" style="margin-top: 4px; color: #909399; font-size: 12px;">
                勾选后，回复群消息时会引用对方的原始消息
              </div>
            </div>
          </div>
        </div>
        
        <!-- 智能体选择 -->
        <div class="form-item">
          <h3>*选择智能体</h3>
          <el-select 
            v-model="staffForm.agentId"
            placeholder="请选择智能体"
            clearable
            style="width: 100%"
          >
            <el-option
              v-for="agent in props.cozeAgents"
              :key="agent.botId"
              :label="agent.name"
              :value="agent.botId"
            >
              <div style="display: flex; align-items: center;">
                <img 
                  :src="`/icon/${agent.platform || 'coze'}.${getPlatformIconExtension(agent.platform)}`" 
                  :alt="agent.platform || 'coze'" 
                  style="width: 18px; height: 18px; margin-right: 8px;"
                />
                <span>{{ agent.name }}</span>
              </div>
            </el-option>
          </el-select>
        </div>
        <!-- 好友标签 -->
        <div class="form-item" v-if="staffForm.chatType === 'single' || staffForm.chatType === 'all'">
          <div class="section-header">
            <div class="title-group">
              <h3>好友标签</h3>
              <p class="description">不选会作为兜底AI助理，回复所有好友</p>
            </div>
            <el-button 
              v-if="isEdit"
              type="warning" 
              size="small"
              @click="resetTags"
              :disabled="staffForm.selectedTags.length === 0"
            >
              重置标签
            </el-button>
          </div>
          <el-checkbox-group v-model="staffForm.selectedTags">
            <el-checkbox 
              v-for="tag in props.contactTags" 
              :key="tag.id" 
              :label="tag.id"
            >
              {{ tag.name }}
            </el-checkbox>
          </el-checkbox-group>
        </div>
        <!-- 群聊标签 -->
        <div class="form-item" v-if="staffForm.chatType === 'group'">
          <div class="section-header">
            <div class="title-group">
              <h3>群聊标签</h3>
              <p class="description">不选会作为兜底AI助理，回复所有群聊</p>
            </div>
            <el-button 
              v-if="isEdit"
              type="warning" 
              size="small"
              @click="resetTags"
              :disabled="staffForm.selectedTags.length === 0"
            >
              重置标签
            </el-button>
          </div>
          <el-checkbox-group v-model="staffForm.selectedTags">
            <el-checkbox 
              v-for="tag in props.groupTags" 
              :key="tag.id" 
              :label="tag.id"
            >
              {{ tag.name }}
            </el-checkbox>
          </el-checkbox-group>
        </div>
        
        <!-- 关键词配置 -->
        <!-- <div class="form-item">
          <div class="section-header">
            <div class="title-group">
              <h3>关键词配置</h3>
              <p class="description">触发关键词回复（非必须）</p>
            </div>
            <el-button 
              type="primary" 
              size="small"
              @click="addKeyword"
              :disabled="staffForm.keywords.length >= 20"
            >
              添加关键词
            </el-button>
          </div>
          <div class="keywords-list">
            <el-tag
              v-for="(keyword, index) in staffForm.keywords"
              :key="index"
              closable
              @close="removeKeyword(index)"
            >
              {{ keyword }}
            </el-tag>
            <el-input
              v-if="keywordInputVisible"
              ref="keywordInputRef"
              v-model="keywordInputValue"
              class="keyword-input"
              size="small"
              @keyup.enter="confirmKeyword"
              @blur="confirmKeyword"
            />
          </div>
        </div> -->
      </div>
      
      <template #footer>
        <div class="dialog-footer">
          <el-button @click="dialogVisible = false">取消</el-button>
          <el-button type="primary" @click="saveStaff">确认</el-button>
        </div>
      </template>
    </el-dialog>
  </template>
  
  <script setup lang="ts">
  import { ref, computed, nextTick, PropType, watch } from 'vue'
  import { ElMessage } from 'element-plus'
  import { Tag } from '@/api/contact'
  // 获取平台图标扩展名
  const getPlatformIconExtension = (platform?: string) => {
    if (platform === 'dify') return 'png'
    if (platform === 'yuanqi') return 'png'
    if (platform === 'fireflow') return 'png'
    return 'svg'
  }
  // 定义组件属性
  const props = defineProps({
    visible: {
      type: Boolean,
      default: false
    },
    staff: {
      type: Object as PropType<{
        id: string
        name: string
        enabled: boolean
        agentId: string
        chatType: 'single' | 'group' | 'all'
        selectedTags: string[]
        keywords: string[]
        readGroupMember?: boolean
        quoteReply?: boolean
      }>,
      default: undefined
    },
    isEdit: {
      type: Boolean,
      default: false
    },
    cozeAgents: {
      type: Array as PropType<Array<{
        name: string,
        botId: string,
        platform: string
      }>>,
      default: () => []
    },
    contactTags: {
      type: Array as PropType<Tag[]>,
      default: () => []
    },
    groupTags: {
      type: Array as PropType<Tag[]>,
      default: () => []
    },
    hasGroupStaff: {
      type: Boolean,
      default: false
    }
  })
  
  // 定义组件事件
  const emit = defineEmits(['update:visible', 'save'])
  const isEditingGroupStaff = computed(() => {
    return props.isEdit && props.staff?.chatType === 'group'
  })
  // 对话框可见性
  const dialogVisible = computed({
    get: () => props.visible,
    set: (val) => emit('update:visible', val)
  })
  
  // 员工表单
  const staffForm = ref({
    id: '',
    name: '',
    enabled: true,
    agentId: '',
    chatType: 'single' as 'single' | 'group' | 'all',
    selectedTags: [] as string[],
    keywords: [] as string[],
    readGroupMember: false,
    quoteReply: false
  })
  
  // 关键词输入控制
  const keywordInputVisible = ref(false)
  const keywordInputValue = ref('')
  const keywordInputRef = ref<HTMLInputElement | null>(null)
  
  // 监听staff属性变化
  watch(() => props.staff, (newVal) => {
    if (newVal) {
      const staffData = JSON.parse(JSON.stringify(newVal))
      staffForm.value = {
        ...staffData,
        readGroupMember: staffData.readGroupMember ?? false,
        quoteReply: staffData.quoteReply ?? false
      }
    }
  }, { immediate: true })
  
  // 关键词相关方法
  const addKeyword = () => {
    keywordInputVisible.value = true
    nextTick(() => {
      keywordInputRef.value?.focus()
    })
  }
  
  const confirmKeyword = () => {
    if (keywordInputValue.value.trim()) {
      if (!staffForm.value.keywords.includes(keywordInputValue.value.trim())) {
        staffForm.value.keywords.push(keywordInputValue.value.trim())
      }
    }
    keywordInputVisible.value = false
    keywordInputValue.value = ''
  }
  
  const removeKeyword = (index: number) => {
    staffForm.value.keywords.splice(index, 1)
  }
  
  // 重置标签选择
  const resetTags = () => {
    staffForm.value.selectedTags = []
    ElMessage.success('已重置，重新保存后生效')
  }
  
  // 保存员工
  const saveStaff = () => {
    // 验证表单
    if (!staffForm.value.name.trim()) {
      ElMessage.error('请输入员工名称')
      return
    }
    
    if (!staffForm.value.agentId) {
      ElMessage.error('请选择智能体')
      return
    }
    
    emit('save', staffForm.value)
  }
  </script>
  
  <style scoped>
  .staff-form {
  padding: 12px 0;
}

.form-item {
  margin-bottom: 18px;
  padding: 16px;
  background-color: #f9f9f9;
  border-radius: 8px;
  border: 1px solid #ebeef5;
  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.03);
}

.form-item:last-child {
  margin-bottom: 0;
}

h3 {
  margin: 0 0 12px 0;
  font-size: 16px;
  color: #303133;
  position: relative;
  padding-left: 12px;
  border-left: 3px solid #409eff;
}

.description {
  margin: 8px 0 16px;
  font-size: 14px;
  color: #909399;
  line-height: 1.4;
}

.section-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 16px;
}

.title-group {
  flex: 1;
}

.title-group h3 {
  margin: 0;
  line-height: 1.2;
}

.keywords-list {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  background-color: #fff;
  padding: 12px;
  border-radius: 6px;
  border: 1px dashed #dcdfe6;
}

.el-tag {
  margin-right: 8px;
  margin-bottom: 8px;
}

.keyword-input {
  width: 120px;
  margin-right: 8px;
  vertical-align: bottom;
}

.dialog-footer {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
}

:deep(.el-checkbox-group) {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  background-color: #fff;
  padding: 12px;
  border-radius: 6px;
  border: 1px solid #ebeef5;
}

:deep(.el-radio-group) {
  display: flex;
  gap: 24px;
  background-color: #fff;
  padding: 12px;
  border-radius: 6px;
  border: 1px solid #ebeef5;
}

:deep(.el-input__wrapper),
:deep(.el-select__wrapper) {
  box-shadow: 0 0 0 1px #dcdfe6 inset;
}

:deep(.el-dialog__header) {
  border-bottom: 1px solid #ebeef5;
  padding-bottom: 16px;
  margin-bottom: 0;
}

:deep(.el-dialog__title) {
  font-weight: bold;
  font-size: 18px;
}

:deep(.el-dialog__footer) {
  border-top: 1px solid #ebeef5;
  padding-top: 16px;
}
  </style>