<template>
  <el-dialog
    v-model="dialogVisible"
    title="添加智能体"
    width="500px"
  >
    <div class="coze-settings">
      <!-- 已添加的智能体列表 -->
      <div class="agents-list" v-if="safeAgents.length">
        <!-- 列表内容保持不变 -->
      </div>
  
      <!-- 添加智能体表单 -->
      <el-form
        ref="agentFormRef"
        :model="agentForm"
        :rules="agentRules"
        label-width="100px"
        class="agent-form"
      >
        <el-form-item label="平台" prop="platform">
          <el-select v-model="agentForm.platform" placeholder="请选择平台">
            <el-option label="Coze" value="coze" />
            <el-option label="Dify" value="dify" />
            <el-option v-if="brandConfig.enableFireflow" label="Fireflow" value="fireflow" />
          </el-select>
        </el-form-item>
        <el-form-item label="智能体名称" prop="name">
          <el-input v-model="agentForm.name" @keydown.enter.prevent placeholder="请输入智能体名称" />
        </el-form-item>
        <!-- 根据平台类型动态显示不同的输入框 -->
        <el-form-item :label="agentForm.platform === 'coze' ? 'Bot ID' : (agentForm.platform === 'fireflow' ? 'API Token' : 'API 秘钥')" prop="botId">
          <el-input 
            v-model="agentForm.botId" 
            @keydown.enter.prevent 
            :placeholder="agentForm.platform === 'coze' ? '请输入 Bot ID' : (agentForm.platform === 'fireflow' ? '请输入 API Token' : '请输入 API 秘钥')"
            :type="(agentForm.platform === 'dify' || agentForm.platform === 'fireflow') ? 'password' : 'text'"
            :show-password="agentForm.platform === 'dify' || agentForm.platform === 'fireflow'"
          />
        </el-form-item>
        <el-form-item label="默认接待">
          <el-switch v-model="agentForm.isDefault" />
        </el-form-item>
      </el-form>
  
      <div class="dialog-footer">
        <el-button @click="handleClose">取消</el-button>
        <el-button 
          type="primary" 
          :icon="Plus"
          @click="handleAdd"
          :disabled="agents.length > 10"
        >
          添加智能体
        </el-button>
      </div>
    </div>
  </el-dialog>
</template>
  
  <script setup lang="ts">
  import { ref, defineProps, defineEmits,watch,computed, inject, type Ref } from 'vue'
  import { ElMessage,FormItemRule } from 'element-plus'
  import { Plus } from '@element-plus/icons-vue'
  import type { CozeAgent } from '@/types/coze'
  import { saveConfig } from '@/api/config'
  import type { BrandConfig } from '@/config/brand'
  
  const brandConfig = inject<Ref<BrandConfig>>('brandConfig', ref({} as BrandConfig))
  
  const props = defineProps<{
  visible: boolean;
  agents: CozeAgent[];
}>()
  
  const emit = defineEmits(['update:visible', 'update:agents'])
  
  const dialogVisible = ref(props.visible)
  const agentFormRef = ref()
  const agentForm = ref({
    name: '',
    botId: '',
    isDefault: false,
    platform: 'coze' // 默认选择 Coze 平台
  })
  const safeAgents = computed(() => Array.isArray(props.agents) ? props.agents : [])
  type ValidateCallback = (error?: Error | string) => void
  type ValidateRule = {
    field: string
    fullField: string
    type: string
    validator: (rule: any, value: string, callback: ValidateCallback) => void
  }

  const agentRules = {
  name: [
    { required: true, message: '请输入智能体名称', trigger: 'blur' }
  ] as FormItemRule[],
  botId: [
    { 
      required: true, 
      validator: (rule: any, value: string, callback: ValidateCallback) => {
        if (!value) {
          const msg = agentForm.value.platform === 'coze' ? '请输入 Bot ID' : (agentForm.value.platform === 'fireflow' ? '请输入 API Token' : '请输入 API 秘钥')
          callback(new Error(msg))
        } else {
          callback()
        }
      },
      trigger: 'blur' 
    },
    {
      validator: async (rule: any, value: string, callback: ValidateCallback) => {
        if (value && checkBotIdExists(value)) {
          callback(new Error('该智能体已经添加过了，无法重复添加'))
        } else {
          callback()
        }
      },
      trigger: 'blur'
    }
  ] as FormItemRule[]
}
  
  // 监听弹窗显示状态
  watch(() => props.visible, (val) => {
    dialogVisible.value = val
  })
  
  watch(() => dialogVisible.value, (val) => {
    emit('update:visible', val)
  })
  // 添加检查 botId 是否存在的方法
const checkBotIdExists = (botId: string): boolean => {
  return safeAgents.value.some(agent => agent.botId === botId)
}
const handleClose = () => {
  dialogVisible.value = false
  agentFormRef.value?.resetFields()
  agentForm.value.isDefault = false  // 重置默认状态
}
  
// 在 handleAdd 方法中添加平台信息
const handleAdd = async () => {
  if (!agentFormRef.value) return
  
  await agentFormRef.value.validate(async (valid: boolean) => {
    if (valid) {
      if (safeAgents.value.length >= 10) {
        ElMessage.warning('最多只能添加10个智能体')
        return
      }

      // 再次检查 botId 是否重复（双重保险）
      if (checkBotIdExists(agentForm.value.botId.trim())) {
        ElMessage.warning('该智能体已经添加过了，无法重复添加')
        return
      }

      // 创建新的智能体对象
      const newAgent: CozeAgent = {
        name: agentForm.value.name.trim(),
        botId: agentForm.value.botId.trim(),
        isDefault: agentForm.value.isDefault,
        platform: agentForm.value.platform // 添加平台信息
      }
      
      // 为 Dify 平台的智能体生成唯一 ID，避免使用秘钥作为 ID
      if (agentForm.value.platform === 'dify') {
        // 使用时间戳和随机字符串生成唯一 ID
        newAgent.id = `dify-${Date.now()}-${Math.random().toString(36).substring(2, 10)}`
      } else {
        // Coze 平台使用 botId 作为 ID
        newAgent.id = agentForm.value.botId.trim()
      }

      // 处理默认智能体逻辑
      const updatedAgents = [...safeAgents.value]
      if (newAgent.isDefault) {
        // 如果新智能体设为默认，取消其他智能体的默认状态
        updatedAgents.forEach(agent => {
          agent.isDefault = false
        })
      } else if (updatedAgents.length === 0) {
        // 如果是第一个智能体，强制设为默认
        newAgent.isDefault = true
      } else if (!updatedAgents.some(agent => agent.isDefault)) {
        // 如果没有默认智能体，将新智能体设为默认
        newAgent.isDefault = true
      }
      
      updatedAgents.push(newAgent)

      try {
        // 保存配置
        const result = await saveConfig('agents', { agents: updatedAgents })
        if (result.success) {
          emit('update:agents', updatedAgents)
          agentFormRef.value.resetFields()
          ElMessage.success('添加成功')
          dialogVisible.value = false
        } else {
          throw new Error(result.error || '添加失败')
        }
      } catch (error) {
        console.error('保存失败:', error)
        ElMessage.error(`添加智能体失败: ${error instanceof Error ? error.message : '未知错误'}`)
      }
    }
  })
}

  </script>
  
  <style scoped>
  .agent-form {
    margin-top: 20px;
  }
  
  .dialog-footer {
    margin-top: 20px;
    text-align: right;
  }
  </style>