        appSecret: feishuConfig.data.feishu_settings.appSecret || '',
        phone: feishuConfig.data.feishu_settings.phone || ''
      }
    }
  } catch (error) {
    console.error('加载配置失败:', error)
    ElMessage.error('加载配置失败')
  }
}

